import{_ as r,o,c as e,ak as a}from"./chunks/framework.oFDsBAuP.js";const n="/settings/token/token-list.png",s="/settings/token/token-create-modal.png",i="/settings/token/token-table-actions.png",m=JSON.parse('{"title":"令牌管理","description":"","frontmatter":{"title":"令牌管理"},"headers":[],"relativePath":"settings/user/token.md","filePath":"settings/user/token.md"}'),l={name:"settings/user/token.md"};function d(g,t,h,p,c,_){return o(),e("div",null,[...t[0]||(t[0]=[a('<h2 id="令牌管理" tabindex="-1">令牌管理 <a class="header-anchor" href="#令牌管理" aria-label="Permalink to &quot;令牌管理&quot;">​</a></h2><p><strong>令牌</strong>即调用开放接口时使用的 API Key：可为不同场景分别创建，单独设置配额、可用模型、IP 与分组等。进入方式：侧栏 <strong>令牌管理</strong>，或浏览器打开 <a href="https://astralink.cc/console/token" target="_blank" rel="noreferrer">控制台 · 令牌管理</a>。</p><p><img src="'+n+'" alt="令牌管理列表页：侧边栏与添加令牌"></p><p>列表中会展示名称、状态、额度、分组、密钥（默认脱敏）、可用模型、IP 限制、创建与最近使用时间等；支持关键字与密钥筛选，以及批量复制、删除所选令牌。</p><h3 id="创建令牌" tabindex="-1"><a href="#创建令牌">创建令牌</a> <a class="header-anchor" href="#创建令牌" aria-label="Permalink to &quot;[创建令牌](#创建令牌)&quot;">​</a></h3><ol><li>点击 <strong>「添加令牌」</strong>，打开创建弹窗。</li><li>填写 <strong>名称</strong>（建议按环境或用途命名，例如「生产网关」「本地调试」）。</li><li>按需选择 <strong>令牌分组</strong>；不选时一般沿用账户默认分组。</li><li>设置 <strong>过期时间</strong>，或使用「永不过期 / 一个月 / 一天 / 一小时」等快捷项。</li><li><strong>新建数量</strong> 大于 1 时，系统会在名称后追加随机后缀，便于批量创建互不冲突的密钥。</li></ol><p><img src="'+s+'" alt="创建新的令牌弹窗"></p><p>填写完成后点击 <strong>「提交」</strong> 保存；若开启无限额度等选项，实际消耗仍受 <strong>账户剩余额度</strong> 约束。</p><h3 id="高级选项说明" tabindex="-1"><a href="#高级选项说明">高级选项说明</a> <a class="header-anchor" href="#高级选项说明" aria-label="Permalink to &quot;[高级选项说明](#高级选项说明)&quot;">​</a></h3><p>弹窗中常见字段含义如下（以控制台实际展示为准）：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>过期时间</td><td>到达后即不可用；支持快捷选择与自定义时间。</td></tr><tr><td>剩余配额</td><td>该令牌允许消耗的上限；用尽后令牌失效。</td></tr><tr><td>无限额度</td><td>关闭后按上面额度限制；开启后令牌侧不封顶，但仍不能超过账户总可用额度。</td></tr><tr><td>模型限制</td><td>仅允许列出的模型；留空通常表示不额外限制（仍受渠道与账户策略影响）。</td></tr><tr><td>IP 白名单</td><td>仅允许来自这些 IP 的请求；留空表示不按 IP 限制。</td></tr><tr><td>分组</td><td>指定令牌走哪一类渠道分组，影响路由与计费策略。</td></tr></tbody></table><h3 id="查看密钥与接入客户端" tabindex="-1"><a href="#查看密钥与接入客户端">查看密钥与接入客户端</a> <a class="header-anchor" href="#查看密钥与接入客户端" aria-label="Permalink to &quot;[查看密钥与接入客户端](#查看密钥与接入客户端)&quot;">​</a></h3><p>创建成功后会回到列表。在 <strong>密钥</strong> 列可点击 <strong>眼睛图标</strong> 临时查看完整 Key，并配合复制操作保存到安全位置（密码管理器或私密配置，勿写入公开仓库）。</p><p>行内 <strong>「聊天」</strong> 下拉中会列出已适配的第三方客户端（如 CC Switch、Cherry Studio 等），可按需一键带入当前令牌，减少手工填地址与密钥的步骤。</p><p><img src="'+i+'" alt="列表中查看密钥与聊天应用集成"></p><p><strong>安全提示：</strong> 令牌与账户资金、调用额度直接相关，勿通过聊天、邮件或截图外泄；泄露后请尽快在控制台 <strong>禁用 / 删除</strong> 并新建令牌。</p><h3 id="编辑与删除" tabindex="-1"><a href="#编辑与删除">编辑与删除</a> <a class="header-anchor" href="#编辑与删除" aria-label="Permalink to &quot;[编辑与删除](#编辑与删除)&quot;">​</a></h3><ul><li><strong>编辑</strong>：在目标行点击 <strong>「编辑」</strong>，可调整名称、额度、模型与 IP 等配置；<strong>密钥字符串本身通常不可在编辑页中修改</strong>，需新建令牌以轮换密钥。</li><li><strong>删除</strong>：点击 <strong>「删除」</strong> 并经确认后，该令牌立即作废且不可恢复；请确认依赖方已更新为新 Key。</li></ul>',18)])])}const u=r(l,[["render",d]]);export{m as __pageData,u as default};
